const outputItems = [];

for (const item of $('final df').all()) {
  const bookData = {
    title: item.json.title,
    authors: item.json.authors,
    isbn: item.json.isbn,
    publisher: item.json.publisher,
    publishedDate: item.json.publishedDate,
    categories: item.json.categories,
    description: item.json.description,
    printType: item.json.printType,
    averageRating: item.json.averageRating,
    amount: item.json.amount,
    currencyCode: item.json.currencyCode,
    smallThumbnail: item.json.smallThumbnail,
    thumbnail: item.json.thumbnail
  };

  outputItems.push({
    json: bookData
  });
}

return outputItems;
